const query = $('Telegram Trigger').first().json.callback_query;
const chatId = String(query.from.id);
const callbackData = query.data;
const messageId = query.message.message_id;
const staticData = $getWorkflowStaticData('global');

if (!staticData.preferences) {
  staticData.preferences = {};
}

if (callbackData === 'menu_ilgi_alanlari') {
  staticData.preferences[chatId] = [];
}

if (!staticData.preferences[chatId]) {
  staticData.preferences[chatId] = [];
}

// Her zaman sadece geçerli kategorileri tut
if (staticData.preferences[chatId]) {
  staticData.preferences[chatId] = staticData.preferences[chatId].filter(t => 
    ['ai', 'bilim', 'dizi_film', 'ekonomi', 'magazin', 'müzik', 'otomotiv', 'sağlık', 'siyaset', 'spor', 'teknoloji', 'yemek'].includes(t)
  );
}

let selectedTopics = [...staticData.preferences[chatId]];

// pref_ ile başlayan ve pref_tamam olmayan callback'leri toggle et
if (callbackData.startsWith('pref_') && callbackData !== 'pref_tamam') {
  const topic = callbackData.replace('pref_', '');
  const index = selectedTopics.indexOf(topic);
  if (index === -1) {
    selectedTopics.push(topic);
  } else {
    selectedTopics.splice(index, 1);
  }
  staticData.preferences[chatId] = selectedTopics;
}

return [{
  json: {
    chat_id: chatId,
    message_id: messageId,
    callback_query_id: query.id,
    callback_data: callbackData,
    username: query.from.username || null,
    full_name: [
      query.from.first_name || "",
      query.from.last_name || ""
    ].join(" ").trim() || null,
    selected_topics: selectedTopics
  }
}];

const data = $('Callback Verisini Çıkar').first().json;
const selected = data.selected_topics;
const chatId = data.chat_id;
const messageId = data.message_id;

const allTopics = [
  { key: "siyaset", emoji: "🗳️", label: "Siyaset" },
  { key: "magazin", emoji: "⭐", label: "Magazin" },
  { key: "ekonomi", emoji: "💰", label: "Ekonomi" },
  { key: "spor", emoji: "⚽", label: "Spor" },
  { key: "bilim", emoji: "🔬", label: "Bilim" },
  { key: "teknoloji", emoji: "💻", label: "Teknoloji" },
  { key: "sağlık", emoji: "🏥", label: "Sağlık" },
  { key: "yemek", emoji: "🍳", label: "Yemek" },
  { key: "otomotiv", emoji: "🚗", label: "Otomotiv" },
  { key: "müzik", emoji: "🎵", label: "Müzik" },
  { key: "dizi_film", emoji: "🎬", label: "Dizi-Film" },
  { key: "ai", emoji: "🤖", label: "AI" }
];

const keyboard = [];

// 3 buton per row (3x4 grid)
for (let i = 0; i < allTopics.length; i += 3) {
  const row = [];
  for (let j = i; j < i + 3 && j < allTopics.length; j++) {
    const t = allTopics[j];
    const isSelected = selected.includes(t.key);
    row.push({
      text: isSelected ? `✅ ${t.emoji} ${t.label}` : `${t.emoji} ${t.label}`,
      callback_data: `pref_${t.key}`
    });
  }
  keyboard.push(row);
}

// Tamam butonu (en altta tek başına)
keyboard.push([{
  text: selected.length > 0 
    ? `✅ Seçimimi Tamamla (${selected.length} seçili)` 
    : '✅ Seçimimi Tamamla',
  callback_data: 'pref_tamam'
}]);

return [{
  json: {
    chat_id: chatId,
    message_id: messageId,
    selected_topics: selected,
    text: '📰 Hangi konularla ilgileniyorsunuz? Birden fazla seçebilirsiniz. Seçimlerinizi tamamlayınca ✅ Tamam butonuna basın!',
    reply_markup: JSON.stringify({ inline_keyboard: keyboard })
  }
}];

