const content = $('Son Dakika Haberleri Getir').first().json.content[0].text;
const data = typeof content === 'string' ? JSON.parse(content) : content;
const news = data.data.news.slice(0, 5);

let summaryMap = {};
try {
  const llmOutput = $('Son Dakika Haber Özetle').first().json.output;
  const cleaned = llmOutput.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  parsed.summaries.forEach(s => { summaryMap[s.id] = s.summary; });
} catch(e) {}

const today = new Date().toLocaleDateString('tr-TR', { 
  day: 'numeric', month: 'long', year: 'numeric', weekday: 'long' 
});

const categoryEmojis = {
  'siyaset': '🗳️', 'magazin': '🎭', 'ekonomi': '💰',
  'spor': '⚽', 'bilim': '🔬', 'teknoloji': '💻',
  'sağlık': '🏥', 'yemek': '🍽️', 'otomotiv': '🚗',
  'müzik': '🎵', 'dizi_film': '🎬', 'ai': '🤖',
  'son_dakika': '🔴', 'genel': '📰', 'dünya': '🌍',
  'gündem': '🇹🇷', 'acil': '🚨'
};

const emojis = ['1️⃣','2️⃣','3️⃣','4️⃣','5️⃣'];

let text = `🔴 Son Dakika\n📅 ${today}\n\n`;

const newsForSave = [];

news.forEach((item, index) => {
  const cat = (item.category || 'son_dakika').toLowerCase();
  const catEmoji = categoryEmojis[cat] || '📰';
  const catName = cat.charAt(0).toUpperCase() + cat.slice(1).replace('_', ' ');
  const summary = summaryMap[item.id] || '';

  text += `${catEmoji} ${catName}\n\n`;
  text += `${emojis[index]} ${item.title}\n`;
  if (summary) text += `📝 ${summary}\n`;
  text += `🔗 <a href="${item.url}">Haberi Oku</a>\n\n—\n\n`;

  newsForSave.push({
    id: item.id,
    title: item.title,
    category: cat,
    url: item.url
  });
});

text += "Detaylı okumak istediğin haberin numarasını söyle! 😊";

const chat_id = $('Kullanıcı Verisini Çıkar').first().json.chat_id;

return [{ json: { 
  text: text.trim(), 
  chat_id: chat_id,
  news_for_save: JSON.stringify(newsForSave)
}}];

